from google.adk.agents import Agent

def prune_context(messages: list, max_tokens: int = 700_000) -> list:
    trimmed = messages.copy()
    while sum(len(m.content) for m in trimmed) > max_tokens and len(trimmed) > 5:
        trimmed.pop(0)
    return trimmed

class ContextAwareAgent(Agent):
    def invoke(self, messages):
        pruned_messages = prune_context(messages)
        return super().invoke(pruned_messages)

import json
from google.adk.sessions import SessionState

def compress_session_state(session: SessionState):
    # Only store delta changes
    state_snapshot = {
        k: getattr(session, k) 
        for k in session._changed_attrs
        if not k.startswith('_')
    }
    return json.dumps(state_snapshot, separators=(',', ':'))

# Usage in agent
session.state = compress_session_state(session)

from google.adk.tools import ToolResponse, tool

@tool
def compact_search(query: str) -> str:
    '''Returns ONLY JSON results, no explanations'''
    results = search_engine(query)
    return json.dumps({
        'hits': [{'title': r.title, 'url': r.url} for r in results[:3]]
    }, separators=(',', ':'))

# Forces compact output
class StrictToolAgent(Agent):
    def parse_tool_output(self, output: str) -> ToolResponse:
        return ToolResponse(content=output[:1000])  # Hard truncate
